#!/usr/bin/env bash
# figma.sh — Figma 决策助手 for Figma 转 Photoshop (PSD).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="Figma 转 Photoshop (PSD)"
TOPIC="Figma"

usage() {
  cat <<EOF
figma.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./figma.sh             # interactive
  ./figma.sh --dry-run   # walk through but no file
  ./figma.sh --json      # JSON to stdout
  ./figma.sh --explain   # show backing playbook rules + mental models
  ./figma.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Figma 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 若需求是「可编辑」→ 选插件 / SVG / PDF 路线并预期手修 → 则 ：留在 Figma 一键 + 尽力保文本用 *PSD Exporter & Importer* 插件（离线）；单个矢量图
  • 如果 若某 layer/group 的有效 blend mode ∉ W3C 16 种 → 把该子树 flatten 成单个像 → 则 ：PS 有 27 种、Figma/web 16-19 种，约 11 种 PS 专有对比/算术模式无源；Figma 的 P
  • 如果 若有文本 → 导出前把每段 AUTO 行高定死成 px、并备好/转曲字体 → 则 ：这是整条流程最高杠杆的单步；AUTO(OpenType `sTypo*`) ≠ PS 120% 会逐行累积错位。`tr

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "若需求是「可编辑」→ 选插件 / SVG / PDF 路线并预期手修"
  "若某 layer/group 的有效 blend mode ∉ W3C 16 种 → 把该子树 flatten 成单个像素层"
  "若有文本 → 导出前把每段 AUTO 行高定死成 px、并备好/转曲字体"
)
declare -a RULE_ACTIONS=(
  "：留在 Figma 一键 + 尽力保文本用 *PSD Exporter & Importer* 插件（离线）；单个矢量图标用 **SVG → PS Place Embedded**（1 SVG=1 Smart Object，绝不用 File→Open）；矢量多、可接受文字转曲用 **PDF → Illustrator(ungroup/unclip) → PS**。案例：一个要持续维护的 logo → 走 SVG→Smart Object，之后双击在 Illustrator 里改。(evidence: [T02-S017, T02-S023, T02-S022])"
  "：PS 有 27 种、Figma/web 16-19 种，约 11 种 PS 专有对比/算术模式无源；Figma 的 Plus darker/lighter 也无精确 PS 对应。案例：用了 Linear Light 的高光层 → 连同被影响区域拍平成一个像素层，锁住屏幕效果。(evidence: [T04-S011, T04-S016, T02-S004])"
  "：这是整条流程最高杠杆的单步；AUTO(OpenType \`sTypo*\`) ≠ PS 120% 会逐行累积错位。\`tracking = round((letterSpacingPx ÷ fontSize) × 1000)\`。案例：Inter 16px AUTO 在 Figma≈19.4px、PS Auto=19.2px，长段落逐行累积偏移 → 导出前统一改成固定 19px。(evidence: [T04-S010, T04-S012, T04-S014, T03-S006])"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "figma-decision"
fi
